from itertools import combinations

def _all_pairings(indices):
    if not indices:
        yield []
        return
    first = indices[0]
    rest = indices[1:]
    for i in range(len(rest)):
        pair = (first, rest[i])
        remaining = rest[:i] + rest[i + 1:]
        for sub in _all_pairings(remaining):
            yield [pair] + sub

class Solution:
    def minimizeMax(self, nums, p):
        if p == 0:
            return 0
        n = len(nums)
        best = None
        for subset in combinations(range(n), 2 * p):
            for pairing in _all_pairings(list(subset)):
                m = max(abs(nums[a] - nums[b]) for a, b in pairing)
                if best is None or m < best:
                    best = m
        return best

