class Solution:
    def minimizeMax(self, nums, p):
        if p == 0:
            return 0
        arr = sorted(nums)
        n = len(arr)
        def count_pairs(d):
            i = 0
            cnt = 0
            while i < n - 1:
                if arr[i + 1] - arr[i] <= d:
                    cnt += 1
                    i += 2
                else:
                    i += 1
            return cnt
        lo, hi = 0, arr[-1] - arr[0]
        while lo < hi:
            mid = (lo + hi) // 2
            if count_pairs(mid) >= p:
                hi = mid
            else:
                lo = mid + 1
        return lo

