var minimizeMax = function(nums, p) {
    if (p === 0) return 0;
    const arr = nums.slice().sort((a, b) => a - b);
    const n = arr.length;
    function countPairs(d) {
        let i = 0, cnt = 0;
        while (i < n - 1) {
            if (arr[i + 1] - arr[i] <= d) {
                cnt++;
                i += 2;
            } else {
                i++;
            }
        }
        return cnt;
    }
    let lo = 0, hi = arr[n - 1] - arr[0];
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (countPairs(mid) >= p) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
